def balanced(s):
    """
    Returns True if the parentheses in the string are balanced.

    :param s: The input string
    :return: Whether the parentheses are balanced
    """
    stack = []
    for c in s:
        if c == '(':
            stack.append(c)
        elif c == ')':
            if not stack:
                return False  # Edge case: an empty string is balanced
            else:
                stack.pop()
    return not stack  # If the stack is empty, then all parentheses were matched
